#include<bits/stdc++.h>
using namespace std;
int n,a[50010],ch[2000010][2],t[2000010],pre[50010],nxt[50010],root[50010],cnt;
pair<int,int> b[50010];
void insert(int x,int pos)
{
    root[pos]=++cnt;
    int now=cnt,lst=root[pos-1];
    t[now]=t[lst]+1;
    for(int i=30;i>=0;i--)
    {
        int k=(x>>i)&1;
        ch[now][k]=++cnt;
        ch[now][k^1]=ch[lst][k^1];
        now=ch[now][k];
        lst=ch[lst][k];
        t[now]=t[lst]+1;
    }
}
int query(int x,int l,int r)
{
    l--;
    int now=root[l],lst=root[r],ans=0;
    for(int i=30;i>=0;i--)
    {
        int k=(x>>i)&1;
        if(t[ch[now][k^1]]-t[ch[lst][k^1]]<0)
        {
            ans+=(1<<i);
            now=ch[now][k^1];
            lst=ch[lst][k^1];
        }
        else
        {
            now=ch[now][k];
            lst=ch[lst][k];
        }
    }
    return ans;
}
int main()
{
    scanf("%d",&n);
    int lst=n+1,fir=0;
    pre[lst]=n;
    nxt[fir]=1;
    a[fir]=a[lst]=1e9;
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        b[i]={a[i],i};
        nxt[i]=i+1;
        pre[i]=i-1;
        insert(a[i],i);
    }
    sort(b+1,b+1+n);
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        int x=b[i].second;
        int l=pre[x],r=nxt[x];
        nxt[l]=r;
        pre[r]=l;
        if(l!=fir)
        {
            ans=max(ans,query(a[x],pre[l]+1,r-1));
        }
        if(r!=lst)
        {
            ans=max(ans,query(a[x],l+1,nxt[r]-1));
        }
    }
    printf("%d",ans);
    return 0;
}
